mapper.update:
UPDATE PRICE_TEMPLATE
SET PRICE = #{price}
WHERE PROGRAM_ID = #{programId}
  AND SESSION_NO = #{sessionNo}
  AND TYPE_ID = #{typeId}
  AND DAY_TYPE = #{dayType}

UPDATE SESSION_TEMPLATE
SET ENABLED = #{enabled}
WHERE PROGRAM_ID = #{programId}
  AND SESSION_NO = #{sessionNo}
  AND DAY_TYPE = #{dayType}

UPDATE PT
SET PT.PRICE = WEEKDAY_PT.PRICE + #{adjustAmount}
FROM PRICE_TEMPLATE PT
INNER JOIN PRICE_TEMPLATE WEEKDAY_PT
	ON PT.PROGRAM_ID = WEEKDAY_PT.PROGRAM_ID
   AND PT.SESSION_NO = WEEKDAY_PT.SESSION_NO
   AND PT.TYPE_ID = WEEKDAY_PT.TYPE_ID
   AND WEEKDAY_PT.DAY_TYPE = 'WEEKDAY'
WHERE PT.PROGRAM_ID = #{programId}
  AND PT.DAY_TYPE = #{dayType}
